final:
module top_module (
    input [1:0] n,
    output reg not_y
);

    always @(*) begin
        case (n)
            2'b00: not_y = 1;
            2'b01: not_y = 1;
            2'b10: not_y = 0;
            2'b11: not_y = 0;
            default: not_y = 0; // Default case
        endcase
    end
endmodule
